<html lang="vi"><head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Stella - Simple is More</title>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700&family=Playfair+Display:ital,wght@0,600;0,700;1,400&display=swap');

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Outfit', sans-serif;
            background: #f8fafc;
            color: #1e293b;
            padding: 0;
            overflow-x: hidden;
        }

        /* Scrollbar */
        ::-webkit-scrollbar {
            width: 8px;
        }
        ::-webkit-scrollbar-track {
            background: #f1f5f9;
        }
        ::-webkit-scrollbar-thumb {
            background: #cbd5e1;
            border-radius: 4px;
        }
        ::-webkit-scrollbar-thumb:hover {
            background: #94a3b8;
        }

        /* Top Utility Promo Bar */
        .promo-bar {
            background: #0f172a;
            color: #f8fafc;
            font-size: 0.75rem;
            padding: 8px 40px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 1px solid rgba(255,255,255,0.05);
        }
        .promo-left strong {
            color: #38bdf8;
        }
        .promo-right span {
            margin: 0 8px;
            opacity: 0.8;
        }

        /* Navbar */
        .navbar {
            background: #ffffff;
            padding: 16px 40px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            box-shadow: 0 4px 20px -2px rgba(15, 23, 42, 0.04);
            position: sticky;
            top: 0;
            z-index: 100;
        }

        .logo {
            font-family: 'Outfit', sans-serif;
            font-size: 1.6rem;
            font-weight: 800;
            color: #0f172a;
            text-decoration: none;
            letter-spacing: -0.03em;
            display: flex;
            align-items: center;
            gap: 6px;
            text-transform: lowercase;
        }
        .logo-icon {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            background: linear-gradient(135deg, #38bdf8, #0ea5e9);
            color: white;
            width: 28px;
            height: 28px;
            border-radius: 6px;
            font-size: 1.1rem;
            font-weight: 700;
            text-transform: uppercase;
        }

        /* Search bar inside navbar */
        .nav-center {
            flex: 0 1 500px;
            margin: 0 20px;
        }
        .search-form {
            display: flex;
            border: 1px solid #e2e8f0;
            border-radius: 9999px;
            overflow: hidden;
            background: #f8fafc;
            transition: all 0.2s ease;
        }
        .search-form:focus-within {
            border-color: #38bdf8;
            box-shadow: 0 0 0 3px rgba(56, 189, 248, 0.12);
            background: white;
        }
        .search-wrapper {
            display: flex;
            align-items: center;
            padding-left: 16px;
            flex: 1;
        }
        .search-icon {
            color: #94a3b8;
        }
        .search-form input {
            width: 100%;
            border: none;
            background: transparent;
            padding: 10px 12px;
            font-size: 0.9rem;
            font-family: inherit;
            color: #1e293b;
            outline: none;
        }
        .search-form input::placeholder {
            color: #94a3b8;
        }
        .search-form button {
            background: #0f172a;
            color: white;
            border: none;
            padding: 0 22px;
            font-size: 0.9rem;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.2s;
        }
        .search-form button:hover {
            background: #0ea5e9;
        }

        /* Nav Actions */
        .nav-right {
            display: flex;
            align-items: center;
            gap: 20px;
        }
        .favorites-link {
            position: relative;
            cursor: pointer;
            color: #64748b;
            transition: color 0.2s;
        }
        .favorites-link:hover {
            color: #0f172a;
        }
        .favorites-link .badge {
            position: absolute;
            top: -6px;
            right: -8px;
            background: #ef4444;
            color: white;
            font-size: 0.65rem;
            font-weight: 700;
            border-radius: 9999px;
            padding: 2px 5px;
            min-width: 16px;
            text-align: center;
        }

        .cart-link {
            display: flex;
            align-items: center;
            gap: 8px;
            text-decoration: none;
            color: #64748b;
            font-weight: 500;
            font-size: 0.9rem;
            transition: color 0.2s;
        }
        .cart-link:hover {
            color: #0f172a;
        }
        .cart-icon-wrapper {
            position: relative;
        }
        .cart-icon-wrapper .badge {
            position: absolute;
            top: -6px;
            right: -8px;
            background: #0ea5e9;
            color: white;
            font-size: 0.65rem;
            font-weight: 700;
            border-radius: 9999px;
            padding: 2px 5px;
            min-width: 16px;
            text-align: center;
        }
        .cart-text {
            font-weight: 600;
        }

        /* User Menu & Dropdown */
        .user-menu {
            position: relative;
            display: inline-block;
        }
        .user-info-trigger {
            display: flex;
            align-items: center;
            gap: 8px;
            cursor: pointer;
        }
        .avatar {
            width: 32px;
            height: 32px;
            background: #e2e8f0;
            color: #475569;
            border-radius: 9999px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            font-size: 0.95rem;
            border: 2px solid #cbd5e1;
        }
        .user-details {
            display: flex;
            flex-direction: column;
            text-align: left;
        }
        .user-welcome {
            font-size: 0.7rem;
            color: #94a3b8;
            line-height: 1;
        }
        .username-text {
            font-size: 0.8rem;
            font-weight: 600;
            color: #334155;
            line-height: 1.3;
        }
        .dropdown-content {
            display: none;
            position: absolute;
            right: 0;
            top: 100%;
            margin-top: 8px;
            background-color: white;
            min-width: 150px;
            box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1);
            border-radius: 8px;
            overflow: hidden;
            z-index: 10;
            border: 1px solid #f1f5f9;
        }
        .user-menu:hover .dropdown-content {
            display: block;
            margin-top: 0;
        }
        .logout-btn {
            width: 100%;
            text-align: left;
            background: none;
            border: none;
            padding: 12px 16px;
            font-size: 0.85rem;
            color: #ef4444;
            cursor: pointer;
            font-weight: 500;
            font-family: inherit;
            display: flex;
            align-items: center;
            gap: 8px;
            transition: background 0.2s;
        }
        .logout-btn:hover {
            background-color: #fef2f2;
        }

        /* Hero Banner Section */
        .hero-banner {
            display: flex;
            background: #e2e8f0;
            border-radius: 0 0 24px 24px;
            overflow: hidden;
            margin-bottom: 40px;
            align-items: stretch;
            min-height: 380px;
        }
        .hero-content {
            flex: 1;
            padding: 48px 60px;
            display: flex;
            flex-direction: column;
            justify-content: center;
            position: relative;
            background: linear-gradient(90deg, rgba(226,232,240,1) 0%, rgba(226,232,240,0.85) 70%, rgba(226,232,240,0) 100%);
            z-index: 2;
        }
        .breadcrumbs {
            font-size: 0.8rem;
            color: #64748b;
            margin-bottom: 24px;
            letter-spacing: 0.05em;
            font-weight: 500;
        }
        .hero-title {
            font-family: 'Playfair Display', serif;
            font-size: 4.2rem;
            font-weight: 700;
            line-height: 1.1;
            color: #0f172a;
            margin-bottom: 12px;
            letter-spacing: -0.02em;
        }
        .hero-title .highlight {
            font-weight: 400;
            font-style: italic;
            color: #475569;
        }
        .hero-subtext {
            font-size: 0.8rem;
            font-weight: 600;
            color: #475569;
            letter-spacing: 0.2em;
            margin-bottom: 20px;
        }
        .hero-labels {
            display: flex;
            gap: 12px;
            margin-top: 10px;
        }
        .limited {
            font-size: 0.75rem;
            font-weight: 700;
            color: #0f172a;
            border-bottom: 2px solid #0f172a;
            padding-bottom: 4px;
            letter-spacing: 0.05em;
        }
        .scroll-down {
            position: absolute;
            right: 40px;
            bottom: 40px;
            width: 44px;
            height: 44px;
            border: 1px solid rgba(15, 23, 42, 0.15);
            border-radius: 9999px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #0f172a;
            cursor: pointer;
            transition: all 0.3s;
        }
        .scroll-down:hover {
            background: #0f172a;
            color: white;
            transform: translateY(4px);
        }

        .hero-image-container {
            flex: 1.2;
            position: relative;
            overflow: hidden;
        }
        .hero-image {
            width: 100%;
            height: 100%;
            object-fit: cover;
            object-position: top center;
            display: block;
        }

        /* Split Main Container */
        .main-container {
            max-width: 1400px;
            margin: 0 auto;
            padding: 0 40px 80px 40px;
            display: grid;
            grid-template-columns: 280px 1fr;
            gap: 40px;
        }

        /* Sidebar Filters */
        .sidebar-filters {
            background: white;
            border-radius: 16px;
            padding: 24px;
            border: 1px solid #f1f5f9;
            align-self: start;
            box-shadow: 0 4px 12px rgba(15, 23, 42, 0.01);
        }
        .filter-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 24px;
            padding-bottom: 12px;
            border-bottom: 1px solid #f1f5f9;
        }
        .filter-header h2 {
            font-size: 1.15rem;
            font-weight: 700;
            color: #0f172a;
        }
        .advanced-link {
            font-size: 0.8rem;
            color: #38bdf8;
            text-decoration: none;
            font-weight: 600;
        }
        .advanced-link:hover {
            color: #0284c7;
        }

        .filter-section {
            margin-bottom: 24px;
            padding-bottom: 20px;
            border-bottom: 1px solid #f1f5f9;
        }
        .filter-section:last-child {
            border-bottom: none;
            margin-bottom: 0;
            padding-bottom: 0;
        }
        .section-title {
            font-size: 0.9rem;
            font-weight: 700;
            color: #0f172a;
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 14px;
            cursor: pointer;
        }
        .arrow-down {
            font-size: 0.65rem;
            color: #94a3b8;
        }

        .brand-search input {
            width: 100%;
            padding: 8px 12px;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            font-size: 0.8rem;
            margin-bottom: 12px;
            font-family: inherit;
            outline: none;
        }
        .brand-search input:focus {
            border-color: #38bdf8;
        }

        .brand-list {
            list-style: none;
        }
        .brand-list li {
            margin-bottom: 8px;
        }
        .brand-item {
            display: flex;
            align-items: center;
            font-size: 0.85rem;
            color: #475569;
            cursor: pointer;
            font-weight: 500;
        }
        .brand-item input {
            margin-right: 10px;
            accent-color: #38bdf8;
