            height: 15px;
            cursor: pointer;
        }
        .brand-item .count {
            margin-left: auto;
            font-size: 0.75rem;
            color: #94a3b8;
        }

        /* Price Range Slider Simulator */
        .price-slider-visual {
            margin: 10px 0 16px 0;
        }
        .slider-chart {
            width: 100%;
            height: 28px;
        }
        .price-inputs {
            display: flex;
            align-items: center;
            gap: 8px;
        }
        .price-inputs input {
            flex: 1;
            width: 100px;
            padding: 8px 10px;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            font-size: 0.8rem;
            text-align: center;
            font-weight: 600;
            color: #334155;
            outline: none;
            background: #f8fafc;
        }
        .price-inputs span {
            font-size: 0.8rem;
            color: #94a3b8;
        }

        /* Size options grid */
        .size-options {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 6px;
        }
        .size-btn {
            background: white;
            border: 1px solid #e2e8f0;
            padding: 6px 0;
            font-size: 0.75rem;
            font-weight: 600;
            color: #475569;
            border-radius: 6px;
            cursor: pointer;
            transition: all 0.2s;
            outline: none;
        }
        .size-btn:hover {
            border-color: #0f172a;
            color: #0f172a;
        }
        .size-btn.active {
            background: #0f172a;
            border-color: #0f172a;
            color: white;
        }

        /* Color Options flex */
        .color-options {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
        }
        .color-dot {
            width: 20px;
            height: 20px;
            border-radius: 9999px;
            border: 1px solid rgba(15,23,42,0.1);
            cursor: pointer;
            transition: all 0.2s;
            position: relative;
        }
        .color-dot.active {
            transform: scale(1.15);
            box-shadow: 0 0 0 2px white, 0 0 0 4px #0f172a;
        }
        .color-black { background: #0f172a; }
        .color-white { background: #ffffff; }
        .color-red { background: #ef4444; }
        .color-yellow { background: #eab308; }
        .color-green { background: #22c55e; }
        .color-blue { background: #3b82f6; }
        .color-purple { background: #a855f7; }
        .color-orange { background: #f97316; }

        /* Right main area */
        .products-area {
            display: flex;
            flex-direction: column;
        }

        /* Controls row */
        .controls-row {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 24px;
        }
        .results-count {
            font-size: 0.9rem;
            font-weight: 500;
            color: #64748b;
        }
        .controls-right {
            display: flex;
            align-items: center;
            gap: 16px;
        }
        .layout-toggle {
            display: flex;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            overflow: hidden;
        }
        .layout-btn {
            background: white;
            border: none;
            padding: 6px 10px;
            cursor: pointer;
            color: #64748b;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
        }
        .layout-btn:hover {
            color: #0f172a;
        }
        .layout-btn.active {
            background: #f1f5f9;
            color: #0f172a;
        }
        .sort-dropdown {
            font-size: 0.85rem;
            color: #475569;
            cursor: pointer;
            border: 1px solid #e2e8f0;
            border-radius: 8px;
            padding: 6px 12px;
            background: white;
        }

        /* Product Grid */
        .product-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(290px, 1fr));
            gap: 24px;
        }

        /* Product Card */
        .product-card {
            background: white;
            border-radius: 16px;
            border: 1px solid #e2e8f0;
            overflow: hidden;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.02), 0 2px 4px -1px rgba(0, 0, 0, 0.01);
            display: flex;
            flex-direction: column;
            height: 100%;
        }
        .product-card:hover {
            transform: translateY(-6px);
            box-shadow: 0 12px 24px -6px rgba(15, 23, 42, 0.08), 0 8px 16px -8px rgba(15, 23, 42, 0.04);
            border-color: #cbd5e1;
        }

        .product-image-container {
            position: relative;
            background: #f8fafc;
            aspect-ratio: 1.1;
            overflow: hidden;
            display: flex;
            align-items: center;
            justify-content: center;
            border-bottom: 1px solid #f1f5f9;
        }
        .product-card-image {
            max-width: 100%;
            max-height: 100%;
            object-fit: contain;
            transition: transform 0.4s ease;
            padding: 15px;
        }
        .product-card:hover .product-card-image {
            transform: scale(1.05);
        }

        .arrival-badge {
            position: absolute;
            top: 14px;
            left: 14px;
            background: #0ea5e9;
            color: white;
            font-size: 0.65rem;
            font-weight: 700;
            padding: 4px 10px;
            border-radius: 9999px;
            letter-spacing: 0.02em;
            z-index: 2;
            box-shadow: 0 2px 6px rgba(56, 189, 248, 0.2);
        }

        .favorite-btn {
            position: absolute;
            bottom: 14px;
            right: 14px;
            background: white;
            border: none;
            width: 34px;
            height: 34px;
            border-radius: 9999px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #94a3b8;
            cursor: pointer;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
            transition: all 0.2s;
            z-index: 2;
        }
        .favorite-btn:hover {
            color: #ef4444;
            transform: scale(1.1);
        }

        .product-details {
            padding: 18px;
            display: flex;
            flex-direction: column;
            flex: 1;
        }

        .product-brand {
            font-size: 0.7rem;
            font-weight: 700;
            text-transform: uppercase;
            color: #94a3b8;
            letter-spacing: 0.08em;
            margin-bottom: 6px;
        }

        .product-name {
            font-size: 0.95rem;
            font-weight: 600;
            color: #0f172a;
            margin-bottom: 12px;
            line-height: 1.4;
            height: 40px;
            display: -webkit-box;
            -webkit-line-clamp: 2;
            -webkit-box-orient: vertical;
            overflow: hidden;
        }

        .price-stock-row {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 14px;
        }

        .price {
            font-size: 1.1rem;
            font-weight: 700;
            color: #0ea5e9;
        }

        .stock {
            font-size: 0.75rem;
            font-weight: 600;
            padding: 2px 8px;
            border-radius: 4px;
        }
        .in-stock {
            color: #10b981;
            background: #ecfdf5;
        }
        .low-stock {
            color: #f59e0b;
            background: #fffbeb;
        }

        .add-btn {
            width: 100%;
            padding: 10px 0;
            background: #0f172a;
            color: white;
            border: none;
            border-radius: 8px;
            cursor: pointer;
            font-size: 0.85rem;
            font-weight: 600;
            transition: all 0.2s;
            box-shadow: 0 2px 4px rgba(15, 23, 42, 0.05);
        }
        .add-btn:hover:not(:disabled) {
            background: #0284c7;
            box-shadow: 0 4px 10px rgba(2, 132, 199, 0.2);
        }
        .add-btn:disabled {
            background: #cbd5e1;
            color: #94a3b8;
            cursor: not-allowed;
            box-shadow: none;
        }

        /* Empty message style */
        .empty-message {
            text-align: center;
            padding: 60px 40px;
            background: white;
            border-radius: 16px;
            border: 1px solid #e2e8f0;
            color: #64748b;
            font-size: 1rem;
            font-weight: 500;
            grid-column: 1 / -1;
        }

        /* Responsive adjustments */
        @media (max-width: 1024px) {
            .main-container {
                grid-template-columns: 1fr;
            }
            .sidebar-filters {
                display: none;
            }
        }
        @media (max-width: 768px) {
            .navbar {
                padding: 16px 20px;
            }
            .nav-center {
                display: none;
            }
            .hero-banner {
                flex-direction: column;
            }
            .hero-content {
                padding: 35px 24px;
            }
            .hero-title {
                font-size: 2.8rem;
            }
            .main-container {
                padding: 0 20px 40px 20px;
            }
        }
    </style>
</head>
<body>
    <!-- Top utility promo bar -->
